import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.boot.context.properties.ConfigurationProperties;
import org.springframework.boot.context.properties.ConfigurationPropertiesScan;
import org.springframework.cache.annotation.EnableCaching;
import org.springframework.scheduling.annotation.EnableAsync;
import org.springframework.stereotype.Service;

@SpringBootApplication
@ConfigurationPropertiesScan   // discovers all @ConfigurationProperties in package
@EnableAsync
@EnableCaching
public class Application {
    public static void main(String[] args) { SpringApplication.run(Application.class, args); }
}

@ConfigurationProperties(prefix = "app")
record AppProps(String name, String version, int maxRequestsPerMinute) {}

@ConfigurationProperties(prefix = "payment.gateway")
record PaymentGatewayProps(String url, int timeoutMs, int maxRetries, String apiKey) {}

@Service
class PaymentService {
    private final AppProps appProps;
    private final PaymentGatewayProps gwProps;

    PaymentService(AppProps a, PaymentGatewayProps g) { appProps = a; gwProps = g; }

    void describe() {
        System.out.println(appProps.name() + " v" + appProps.version());
        System.out.println("Gateway: " + gwProps.url() + " (timeout: " + gwProps.timeoutMs() + "ms)");
    }
}

import jakarta.validation.constraints.*;
import org.springframework.boot.context.properties.ConfigurationProperties;
import org.springframework.validation.annotation.Validated;

@ConfigurationProperties(prefix = "payment.gateway")
@Validated
public record PaymentGatewayProps(
    @NotBlank(message = "payment.gateway.url is required")
    @Pattern(regexp = "https://.*",
             message = "payment.gateway.url must use HTTPS")
    String url,

    @Min(value = 100, message = "timeout must be at least 100ms")
    @Max(value = 30000, message = "timeout cannot exceed 30 seconds")
    int timeoutMs,

    @Min(value = 1, message = "maxRetries must be at least 1")
    @Max(value = 5, message = "maxRetries cannot exceed 5")
    int maxRetries,

    @NotBlank(message = "payment.gateway.api-key is required")
    String apiKey
) {}

// This application.properties would FAIL at startup:
// payment.gateway.url=http://api.razorpay.com  ← doesn't match 'https://.*'
// payment.gateway.timeout-ms=99               ← below @Min(100)
// payment.gateway.api-key=                    ← blank string violates @NotBlank

