import org.springframework.boot.context.properties.ConfigurationProperties;
import org.springframework.validation.annotation.Validated;
import org.springframework.stereotype.Service;

@ConfigurationProperties(prefix = "notification")
public record NotificationProps(
    boolean enabled,
    Email email,
    Sms sms
) {
    public record Email(
        String host,
        int port,
        String from,
        boolean tlsEnabled      // notification.email.tls-enabled
    ) {}

    public record Sms(
        String url,
        String apiKey,          // notification.sms.api-key
        int maxPerDay           // notification.sms.max-per-day
    ) {}
}

// application.properties:
// notification.enabled=true
// notification.email.host=smtp.gmail.com
// notification.email.port=587
// notification.email.from=noreply@example.com
// notification.email.tls-enabled=true
// notification.sms.url=https://api.sms.in
// notification.sms.api-key=${SMS_KEY}
// notification.sms.max-per-day=1000

@Service
class NotificationService {
    private final NotificationProps props;
    NotificationService(NotificationProps p) { props = p; }

    void sendEmail(String to, String body) {
        if (!props.enabled()) return;
        System.out.printf("Connecting to %s:%d (TLS:%b) from %s%n",
            props.email().host(), props.email().port(),
            props.email().tlsEnabled(), props.email().from());
    }

    void sendSms(String to, String msg) {
        if (!props.enabled()) return;
        System.out.printf("SMS via %s (limit %d/day)%n",
            props.sms().url(), props.sms().maxPerDay());
    }
}

