// Approach: prove valid config loads correctly, explain what fails
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.test.context.ActiveProfiles;
import org.springframework.test.context.TestPropertySource;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

// Test with VALID properties — should pass:
@SpringBootTest(webEnvironment=SpringBootTest.WebEnvironment.NONE)
@TestPropertySource(properties = {
    "payment.gateway.url=https://sandbox.razorpay.com",
    "payment.gateway.timeout-ms=5000",
    "payment.gateway.max-retries=3",
    "payment.gateway.api-key=test_key_123"
})
class ValidConfigTest {
    @Autowired PaymentGatewayProps props;
    @Test void validConfig_loadsSuccessfully() {
        assertEquals("https://sandbox.razorpay.com", props.url());
        assertEquals(3, props.maxRetries());
    }
}

// Test with INVALID properties — context fails to start:
// @SpringBootTest loads context; missing required property causes failure:
// Cannot create test class because context initialization failed.
// Error: payment.gateway.url must not be blank
//
// To verify programmatically:
class InvalidConfigExplained {
    // When application.properties has: payment.gateway.url= (blank)
    // And @Validated is on PaymentGatewayProps
    // And @NotBlank is on url field
    // → Application context fails with:
    // 'payment.gateway.url' failed validation: must not be blank
    // The @SpringBootTest would throw an exception during context init
    void explanation() {
        System.out.println("@Validated + @NotBlank on @ConfigurationProperties:");
        System.out.println("- Application REFUSES to start with blank/missing required properties");
        System.out.println("- Error shown at startup, not at first method call");
        System.out.println("- This is the fail-fast advantage over @Value");
    }
}

